Write-Host "Original data has $($originalTests.Count) tests"

# Load current tests
$json = Get-Content "lib/data/all-tests.json" -Raw | ConvertFrom-Json
$currentTests = $json.allTests | ForEach-Object { $_.name }

Write-Host "Current database has $($currentTests.Count) tests"

# Find missing tests
$missing = @()
foreach ($test in $originalTests) {
    if ($currentTests -notcontains $test) {
        $missing += $test
    }
}

if ($missing.Count -gt 0) {
    Write-Host "`nMissing tests: $($missing.Count)"
    $missing | ForEach-Object { Write-Host "  - $_" }
} else {
    Write-Host "`nAll original tests are present!"
}

# Find extra tests (not in original)
$extra = @()
foreach ($test in $currentTests) {
    if ($originalTests -notcontains $test) {
        $extra += $test
    }
}

if ($extra.Count -gt 0) {
    Write-Host "`nExtra tests in database (not in original): $($extra.Count)"
    $extra | Select-Object -First 20 | ForEach-Object { Write-Host "  + $_" }
    if ($extra.Count -gt 20) {
        Write-Host "  ... and $($extra.Count - 20) more"
    }
}
